// === CONFIG (edite aqui) ===
const MODE = 'fair';        // fair | biased | markov | periodic
const WHEEL_TYPE = 'european';
const WHEEL_ID = 'sim-mesa-1';
const SPINS_PER_TICK = 200;
const BIAS_STRENGTH = 0.25;     // biased
const DEPENDENCE = 0.6;         // markov
const PERIOD = 5;               // periodic
const PERIOD_STRENGTH = 0.6;    // periodic
const HOT = [19, 4, 21, 2, 25]; // setor quente (biased)
// drift = rode em 'fair' e depois troque para 'biased' com o workflow ativo
// ===========================
const P = 37;
const out = [];
const buf = [];
let prev = Math.floor(Math.random() * P);
for (let k = 0; k < SPINS_PER_TICK; k++) {
  let v;
  if (MODE === 'biased' && Math.random() < BIAS_STRENGTH) {
    v = HOT[Math.floor(Math.random() * HOT.length)];
  } else if (MODE === 'markov' && k > 0 && Math.random() < DEPENDENCE) {
    v = (7 * prev + 13) % P;
  } else if (MODE === 'periodic' && k >= PERIOD && Math.random() < PERIOD_STRENGTH) {
    v = buf[k - PERIOD];
  } else {
    v = Math.floor(Math.random() * P);
  }
  buf.push(v);
  prev = v;
  out.push({ json: { wheel_id: WHEEL_ID, wheel_type: WHEEL_TYPE, number: String(v), timestamp: new Date().toISOString() } });
}
return out;
